import React from "react";

function App() {
  const [html, setHtml] = React.useState("<h1>Hello</h1>");
  const [css, setCss] = React.useState("h1 {color:red}");
  const [js, setJs] = React.useState("");

  const output = `
    <html>
      <style>${css}</style>
      <body>
        ${html}
        <script>${js}<\/script>
      </body>
    </html>
  `;

  return (
    <div style={{textAlign:"center"}}>
      <h1>🔥 CodeSnip</h1>

      <textarea value={html} onChange={e=>setHtml(e.target.value)} />
      <textarea value={css} onChange={e=>setCss(e.target.value)} />
      <textarea value={js} onChange={e=>setJs(e.target.value)} />

      <h2>Output:</h2>

      <iframe
        srcDoc={output}
        title="output"
        sandbox="allow-scripts"
        width="100%"
        height="300px"
      />
    </div>
  );
}

export default App;
